// === What the macro GENERATES for a concrete struct ===
// Given:
//   #[derive(Summary)]
//   struct User { name: String, age: u32, active: bool }
//
// The macro expands to exactly:

pub trait Summary {
    fn summarize(&self);
    fn fields() -> &'static [&'static str] where Self: Sized;
}

#[derive(Debug)]
struct User {
    name: String,
    age: u32,
    active: bool,
}

// This is what #[derive(Summary)] would generate:
impl Summary for User {
    fn summarize(&self) {
        println!("[User]");
        println!("  {}: {:?}", "name", self.name);
        println!("  {}: {:?}", "age", self.age);
        println!("  {}: {:?}", "active", self.active);
    }

    fn fields() -> &'static [&'static str] {
        &["name", "age", "active"]
    }
}

#[derive(Debug)]
struct Config {
    host: String,
    port: u16,
    debug: bool,
    workers: usize,
}

impl Summary for Config {
    fn summarize(&self) {
        println!("[Config]");
        println!("  {}: {:?}", "host", self.host);
        println!("  {}: {:?}", "port", self.port);
        println!("  {}: {:?}", "debug", self.debug);
        println!("  {}: {:?}", "workers", self.workers);
    }

    fn fields() -> &'static [&'static str] {
        &["host", "port", "debug", "workers"]
    }
}

fn print_summary<T: Summary>(item: &T) {
    item.summarize();
}

fn main() {
    let user = User { name: "Alice".into(), age: 30, active: true };
    let config = Config { host: "localhost".into(), port: 8080, debug: false, workers: 4 };

    print_summary(&user);
    println!();
    print_summary(&config);
    println!();

    println!("User fields: {:?}", User::fields());
    println!("Config fields: {:?}", Config::fields());
}
```

Proc macro crate setup requirements:
- The derive crate must have `proc-macro = true` in `[lib]` — it produces a shared library the compiler loads.
- `syn` parses the `TokenStream` into a typed AST (`DeriveInput`). Use `features = ["full"]` for statement/expression parsing.
- `quote!` produces `TokenStream2` (proc_macro2). Interpolation uses `#ident`, `#( #iter )*` for repetition.
- The final `TokenStream::from(expanded)` converts from `proc_macro2` back to the compiler's `proc_macro::TokenStream`.
- Run `cargo expand` (cargo-expand tool) to see what your macro actually generates — essential for debugging.

```rust
// === Crate: log_call_macro/src/lib.rs ===
// [lib] proc-macro = true
// [dependencies] syn = {version="2", features=["full"]}, quote="1", proc-macro2="1"

