// src/ring_buffer.rs — the implementation under test
#[derive(Debug, Clone)]
pub struct RingBuffer<T> {
    buf: std::collections::VecDeque<T>,
    capacity: usize,
}

impl<T: Clone> RingBuffer<T> {
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0);
        RingBuffer { buf: std::collections::VecDeque::with_capacity(capacity), capacity }
    }
    pub fn push(&mut self, item: T) -> Option<T> {
        let dropped = if self.buf.len() == self.capacity { self.buf.pop_front() } else { None };
        self.buf.push_back(item);
        dropped
    }
    pub fn pop(&mut self) -> Option<T> { self.buf.pop_front() }
    pub fn peek(&self) -> Option<&T> { self.buf.front() }
    pub fn len(&self) -> usize { self.buf.len() }
    pub fn capacity(&self) -> usize { self.capacity }
    pub fn is_empty(&self) -> bool { self.buf.is_empty() }
    pub fn is_full(&self) -> bool { self.buf.len() == self.capacity }
    pub fn iter(&self) -> impl Iterator<Item = &T> { self.buf.iter() }
    pub fn to_vec(&self) -> Vec<T> where T: Clone { self.buf.iter().cloned().collect() }
}

// tests/proptest_ring_buffer.rs
#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;
    use proptest::collection::vec;

    // --- Custom strategy: generate a valid capacity ---
    fn capacity_strategy() -> impl Strategy<Value = usize> {
        1usize..=32
    }

    // --- Custom strategy: sequence of operations ---
    #[derive(Debug, Clone)]
    enum Op {
        Push(i32),
        Pop,
    }

    fn op_strategy() -> impl Strategy<Value = Op> {
        prop_oneof![
            any::<i32>().prop_map(Op::Push),
            Just(Op::Pop),
        ]
    }

    fn ops_strategy() -> impl Strategy<Value = Vec<Op>> {
        vec(op_strategy(), 0..50)
    }

    // --- Property 1: len never exceeds capacity ---
    proptest! {
        #[test]
        fn len_never_exceeds_capacity(
            capacity in capacity_strategy(),
            items in vec(any::<i32>(), 0..100)
        ) {
            let mut rb = RingBuffer::new(capacity);
            for item in items {
                rb.push(item);
                prop_assert!(
                    rb.len() <= rb.capacity(),
                    "len {} > capacity {}", rb.len(), rb.capacity()
                );
            }
        }
    }

    // --- Property 2: push then pop returns the pushed value (when not overwritten) ---
    proptest! {
        #[test]
        fn push_pop_roundtrip_when_not_full(
            capacity in 2usize..=16,
            value in any::<i32>()
        ) {
            let mut rb = RingBuffer::new(capacity);
            // With an empty buffer and capacity > 1, a single push then pop should return value
            rb.push(value);
            let popped = rb.pop();
            prop_assert_eq!(popped, Some(value));
        }
    }

    // --- Property 3: FIFO ordering is preserved ---
    proptest! {
        #[test]
        fn fifo_ordering_preserved(
            capacity in capacity_strategy(),
            items in vec(any::<i32>(), 0..20usize)
        ) {
            let mut rb = RingBuffer::new(capacity);
            // Only push up to capacity to avoid eviction
            let limited: Vec<i32> = items.into_iter().take(capacity).collect();
            for &item in &limited {
                rb.push(item);
            }
            let mut popped = Vec::new();
            while let Some(v) = rb.pop() {
                popped.push(v);
            }
            prop_assert_eq!(popped, limited, "FIFO ordering violated");
        }
    }

    // --- Property 4: when buffer is full, oldest element is evicted ---
    proptest! {
        #[test]
        fn eviction_removes_oldest(
            capacity in 1usize..=8,
            extra in 1usize..=8
        ) {
            let mut rb = RingBuffer::new(capacity);
            // Fill to capacity with 0..capacity
            for i in 0..capacity as i32 {
                rb.push(i);
            }
            prop_assert!(rb.is_full());

            // Push `extra` more items — each should evict the corresponding old item
            for i in 0..extra as i32 {
                let dropped = rb.push(capacity as i32 + i);
                prop_assert_eq!(dropped, Some(i), "Expected oldest item {} to be evicted", i);
            }
        }
    }

    // --- Property 5: model-based testing (RingBuffer vs Vec model) ---
    proptest! {
        #[test]
        fn matches_vec_model(capacity in capacity_strategy(), ops in ops_strategy()) {
            let mut rb = RingBuffer::new(capacity);
            // Model: a simple Vec that mimics the ring buffer behavior
            let mut model: std::collections::VecDeque<i32> = std::collections::VecDeque::new();

            for op in ops {
                match op {
                    Op::Push(v) => {
                        if model.len() == capacity { model.pop_front(); }
                        model.push_back(v);
                        rb.push(v);
                    }
                    Op::Pop => {
                        let rb_result = rb.pop();
                        let model_result = model.pop_front();
                        prop_assert_eq!(rb_result, model_result);
                    }
                }
                // Invariant: contents must match the model at every step
                let rb_contents: Vec<i32> = rb.iter().cloned().collect();
                let model_contents: Vec<i32> = model.iter().cloned().collect();
                prop_assert_eq!(rb_contents, model_contents, "State diverged from model");
            }
        }
    }

    // --- Property 6: demonstrating shrinking ---
    // If we introduce a bug: comment out the eviction check and see proptest find the MINIMAL failing case
    proptest! {
        #[test]
        fn shrinking_demo_len_monotone(capacity in 1usize..=10, items in vec(0i32..100, 0..20)) {
            let mut rb = RingBuffer::new(capacity);
            let mut prev_len = 0;
            for item in &items {
                rb.push(*item);
                // Property: len increases by 1 until full, then stays at capacity
                let expected_len = (prev_len + 1).min(capacity);
                prop_assert_eq!(rb.len(), expected_len,
                    "len mismatch after push: expected {expected_len}, got {}", rb.len());
                prev_len = rb.len();
            }
        }
    }
}
```

Proptest concepts:
- **Strategies**: `any::<T>()` generates arbitrary `T`; `1usize..=32` generates a range; `prop_oneof!` picks between strategies with equal weight; `prop_map` transforms a generated value.
- **Shrinking**: when a test fails, proptest automatically shrinks the input to the **minimal failing case**. A 50-element `ops` sequence will shrink down to the 3-operation sequence that exposes the bug. This is automatic — unlike QuickCheck, proptest strategies carry their own shrinkers.
- **Model-based testing**: Property 5 compares the real implementation against a simple reference model on every operation. This finds bugs that are only visible after specific sequences of operations.
- **`prop_assert!`**: like `assert!` but returns `Err` instead of panicking, allowing proptest to catch and shrink the failure. Use `prop_assert!` inside proptest blocks, never bare `assert!`.
- Configuration: `ProptestConfig::with_cases(10_000)` increases the number of test cases; the default is 256.

```rust
// Zero-cost abstractions: the abstraction boundary disappears at compile time.
// We demonstrate this with three implementations of "sum a slice of numbers"
// and show they produce identical assembly.

// --- Version 1: hand-written, maximally explicit ---
fn sum_i32_explicit(data: &[i32]) -> i32 {
    let mut total = 0i32;
    let mut i = 0;
    while i < data.len() {
        total = total.wrapping_add(data[i]);
        i += 1;
    }
    total
}

// --- Version 2: generic with trait bound ---
use std::ops::Add;
use std::iter::Sum;

#[inline]
fn sum_generic<T>(data: &[T]) -> T
where
    T: Sum + Copy,
{
    data.iter().copied().sum()
}

// --- Version 3: iterator adaptor chain ---
#[inline]
fn sum_iter_chain(data: &[i32]) -> i32 {
    data.iter()
        .copied()
        .filter(|&x| x >= 0) // add some complexity to show it still compiles away
        .fold(0i32, |acc, x| acc.wrapping_add(x))
}

// --- Trait object (DOES have overhead) vs generic (zero-cost) ---

trait Transformer {
    fn transform(&self, x: f64) -> f64;
}

struct Scale(f64);
struct Offset(f64);

impl Transformer for Scale  { fn transform(&self, x: f64) -> f64 { x * self.0 } }
impl Transformer for Offset { fn transform(&self, x: f64) -> f64 { x + self.0 } }

// Monomorphized: compiler generates a separate function for each T.
// The call to t.transform() is DIRECT — no indirection.
#[inline]
fn apply_generic<T: Transformer>(t: &T, data: &mut [f64]) {
    for x in data.iter_mut() {
        *x = t.transform(*x);
    }
}

// Dynamic dispatch: function pointer table lookup per call.
// Use only when you genuinely need runtime polymorphism.
fn apply_dyn(t: &dyn Transformer, data: &mut [f64]) {
    for x in data.iter_mut() {
        *x = t.transform(*x); // vtable lookup: ~1ns penalty per call
    }
}

// --- Newtype abstraction: zero overhead wrapper ---

#[repr(transparent)] // guaranteed same layout as inner type
struct Celsius(f64);

#[repr(transparent)]
struct Fahrenheit(f64);

impl Celsius {
    #[inline(always)]
    fn to_fahrenheit(self) -> Fahrenheit {
        Fahrenheit(self.0 * 9.0 / 5.0 + 32.0)
    }
}

// This function is identical in assembly to: fn convert(c: f64) -> f64 { c * 9.0/5.0 + 32.0 }
// The Celsius/Fahrenheit types are erased. #[repr(transparent)] guarantees no padding.
#[inline(always)]
fn batch_convert(temps: &[Celsius]) -> Vec<Fahrenheit> {
    // SAFETY: Celsius and Fahrenheit are #[repr(transparent)] over f64
    // For demonstration purposes, show the zero-cost path manually:
    temps.iter().map(|&Celsius(c)| Fahrenheit(c * 9.0 / 5.0 + 32.0)).collect()
}

// --- Verifying with std::hint::black_box in a benchmark context ---

#[cfg(test)]
mod tests {
    use super::*;
    use std::hint::black_box;

    #[test]
    fn results_are_identical() {
        let data: Vec<i32> = (1..=1000).collect();

        let r1 = sum_i32_explicit(black_box(&data));
        let r2 = sum_generic::<i32>(black_box(&data));
        let r3: i32 = data.iter().copied().sum();

        assert_eq!(r1, r2);
        assert_eq!(r2, r3);
        // All three produce 500500
    }

    #[test]
    fn generic_vs_dyn_produce_same_results() {
        let mut a = vec![1.0f64, 2.0, 3.0, 4.0, 5.0];
        let mut b = a.clone();
        let scale = Scale(2.0);

        apply_generic(&scale, &mut a);
        apply_dyn(&scale, &mut b);

        assert_eq!(a, b); // same result, different overhead
    }

    #[test]
    fn newtype_convert() {
        let temps = vec![Celsius(0.0), Celsius(100.0), Celsius(-40.0)];
        let converted = batch_convert(&temps);
        let values: Vec<f64> = converted.into_iter().map(|Fahrenheit(f)| f).collect();
        assert!((values[0] - 32.0).abs() < 1e-10);
        assert!((values[1] - 212.0).abs() < 1e-10);
        assert!((values[2] - (-40.0)).abs() < 1e-10);
    }
}

fn main() {
    let data: Vec<i32> = (1..=100).collect();
    println!("explicit: {}", sum_i32_explicit(&data));
    println!("generic:  {}", sum_generic::<i32>(&data));
    println!("iter:     {}", sum_iter_chain(&data));
    // All print 5050

    // To inspect assembly:
    // cargo rustc --release -- --emit asm
    // Look for sum_i32_explicit and sum_generic<i32>:
    // they will be identical or near-identical vectorized loops.
}
```

To verify zero-cost: `cargo install cargo-asm && cargo asm --release 'crate::sum_generic<i32>'` — compare with `sum_i32_explicit`. On x86-64, both produce SIMD-vectorized loops using `vpaddd` with identical structure.

When abstractions ARE zero-cost:
- Generics (`<T: Trait>`) — monomorphized, direct call, inlinable.
- `impl Trait` in argument position — same as generic.
- `#[repr(transparent)]` newtypes — zero padding, cast-compatible.
- Iterator chains — fused and inlined by LLVM into a single loop.

When they are NOT zero-cost:
- `dyn Trait` — vtable pointer per object, indirect function call, cannot inline.
- `Box<dyn Trait>` — heap allocation + vtable.
- `Rc<RefCell<T>>` — reference counting + runtime borrow check.

