use std::mem;

// --- Stack vs Heap: the fundamentals ---

#[derive(Debug)]
struct Point { x: f64, y: f64 } // 16 bytes, trivially stack-allocated

#[derive(Debug)]
struct Matrix4x4([f64; 16]); // 128 bytes — still stack, but larger

fn stack_vs_heap_basics() {
    // Stack: allocated at compile time, freed on scope exit, zero cost
    let p = Point { x: 1.0, y: 2.0 }; // stack
    let arr = [0i32; 64]; // 256 bytes on stack
    println!("Point size: {} bytes", mem::size_of::<Point>());
    println!("arr lives at: {:p}", &arr);

    // Heap: allocated at runtime via allocator, must be freed explicitly
    // Box<T> = heap allocation for exactly one T
    let boxed_p = Box::new(Point { x: 3.0, y: 4.0 }); // heap
    println!("boxed_p lives at: {:p}", boxed_p.as_ref() as *const _);
    // Box is freed when it drops — RAII, no manual free()

    // Vec<T> = heap-allocated, growable array
    let mut v: Vec<i32> = Vec::with_capacity(64); // heap, 64 i32 slots reserved
    v.extend(0..32);
    println!("Vec ptr: {:p}, len: {}, cap: {}", v.as_ptr(), v.len(), v.capacity());
}

// --- When Box is appropriate ---

// 1. Recursive types: size is infinite without indirection
#[derive(Debug)]
enum List<T> {
    Cons(T, Box<List<T>>), // Box breaks the infinite size cycle
    Nil,
}

// 2. Trait objects: type-erased heap values
fn make_formatter(uppercase: bool) -> Box<dyn Fn(&str) -> String> {
    if uppercase {
        Box::new(|s: &str| s.to_uppercase())
    } else {
        Box::new(|s: &str| s.to_lowercase())
    }
}

// 3. Moving large data without stack copying
fn expensive_process(data: Box<Matrix4x4>) -> Box<Matrix4x4> {
    // data moves as a pointer (8 bytes), not 128 bytes of memcpy
    data // returned as pointer, no copy
}

// --- Stack arrays vs Vec ---

fn array_vs_vec() {
    // Stack array: size must be known at compile time, lives on stack
    // Best for: small, fixed-size, performance-critical buffers
    let mut buf = [0u8; 256]; // 256 bytes on stack, zero initialization
    buf[0] = 42;
    println!("Stack buf address: {:p}", buf.as_ptr());

    // Vec: size known at runtime, heap-allocated, growable
    // Best for: dynamic sizes, large data, returning from functions
    let runtime_size = std::env::args().count() * 100;
    let heap_buf: Vec<u8> = vec![0u8; runtime_size];
    println!("Heap buf address: {:p}", heap_buf.as_ptr());

    // DANGER: large stack arrays cause stack overflow
    // let huge = [0u8; 10_000_000]; // likely stack overflow!
    // FIX: use Vec or Box
    let huge: Vec<u8> = vec![0u8; 10_000_000]; // safe: heap
    println!("Huge vec: {} bytes on heap", huge.len());

    // Initializing a fixed-size array without stack overflow:
    let boxed_arr: Box<[u8; 1_000_000]> = vec![0u8; 1_000_000]
        .into_boxed_slice()
        .try_into()
        .unwrap(); // converts Box<[u8]> -> Box<[u8; N]>
    println!("Boxed array: {} bytes on heap", boxed_arr.len());
}

// --- sizeof and layout ---

fn layout_demo() {
    println!("u8:      {} byte",  mem::size_of::<u8>());
    println!("i32:     {} bytes", mem::size_of::<i32>());
    println!("f64:     {} bytes", mem::size_of::<f64>());
    println!("&str:    {} bytes", mem::size_of::<&str>());    // 16: ptr + len
    println!("String:  {} bytes", mem::size_of::<String>()); // 24: ptr + len + cap
    println!("Vec<i32>:{} bytes", mem::size_of::<Vec<i32>>());// 24: ptr + len + cap
    println!("Box<i32>:{} bytes", mem::size_of::<Box<i32>>()); // 8: just a pointer
    println!("Option<Box<i32>>: {} bytes", mem::size_of::<Option<Box<i32>>>());
    // 8 — null pointer optimization: None = null pointer

    // Box<T>: pointer size, regardless of T
    println!("Box<Matrix4x4>: {} bytes on stack", mem::size_of::<Box<Matrix4x4>>());
    println!("Matrix4x4 itself: {} bytes", mem::size_of::<Matrix4x4>());
}

// --- Decision guide as code ---

fn choose_allocation<T>(n: usize) {
    // Use stack array when:
    // - size is known at compile time
    // - small (< ~1MB)
    // - hot path, no heap indirection wanted
    // let arr: [T; 8] = ...

    // Use Box<T> when:
    // - T is large and you want a stable address
    // - recursive/self-referential type
    // - trait object (Box<dyn Trait>)
    // let b: Box<T> = Box::new(value);

    // Use Vec<T> when:
    // - size unknown at compile time
    // - need to grow/shrink
    // - returning from a function
    let v: Vec<u8> = vec![0; n];
    let _ = v;

    // Use Box<[T]> (boxed slice) when:
    // - size known at runtime but never changes
    // - want Vec semantics but save the `capacity` word
    // mem::size_of::<Box<[T]>>() == 16 vs mem::size_of::<Vec<T>>() == 24
    let frozen: Box<[u8]> = vec![0u8; n].into_boxed_slice();
    println!("Frozen {} bytes", frozen.len());
}

fn main() {
    stack_vs_heap_basics();
    println!();
    array_vs_vec();
    println!();
    layout_demo();
    println!();
    choose_allocation::<u8>(64);

    let fmt = make_formatter(true);
    println!("{}", fmt("hello world"));

    let list = List::Cons(1, Box::new(List::Cons(2, Box::new(List::Nil))));
    println!("{list:?}");
}
```

Allocation decision flowchart:
1. **Size known at compile time and small (< ~64KB)?** → stack array `[T; N]`.
2. **Need runtime-determined size or dynamic growth?** → `Vec<T>`.
3. **Fixed runtime size, never grows?** → `Box<[T]>` (saves 8 bytes vs Vec, no capacity field).
4. **Single large value you want to heap-allocate?** → `Box<T>`.
5. **Trait object or recursive type?** → `Box<dyn Trait>` or `Box<RecursiveType>`.

The stack is typically 8MB on Linux/macOS — large arrays (> ~1MB) must go on the heap.

```rust
use std::marker::PhantomData;
use std::io::{self, Write, Read};

// --- State marker types (uninhabited — cannot be constructed) ---
pub enum Disconnected {}
pub enum Connected {}
pub enum TlsHandshaking {}
pub enum Authenticated {}

// --- The connection type, parameterized on state ---
pub struct TcpConn<S> {
    // In a real impl: TcpStream, buffers, etc.
    addr: String,
    _state: PhantomData<S>,
}

// --- Methods available in ALL states ---
impl<S> TcpConn<S> {
    pub fn remote_addr(&self) -> &str { &self.addr }
}

// --- Disconnected: the initial state ---
impl TcpConn<Disconnected> {
    pub fn new(addr: impl Into<String>) -> Self {
        TcpConn { addr: addr.into(), _state: PhantomData }
    }

    /// Consumes the Disconnected connection, returns a Connected one.
    /// Transition: Disconnected -> Connected
    pub fn connect(self) -> Result<TcpConn<Connected>, io::Error> {
        println!("[tcp] Connecting to {}...", self.addr);
        // Real impl: TcpStream::connect(&self.addr)
        Ok(TcpConn { addr: self.addr, _state: PhantomData })
    }
}

// --- Connected: can send/receive or start TLS ---
impl TcpConn<Connected> {
    pub fn send(&mut self, data: &[u8]) -> Result<usize, io::Error> {
        println!("[tcp] Sending {} bytes", data.len());
        Ok(data.len())
    }

    pub fn recv(&mut self, buf: &mut [u8]) -> Result<usize, io::Error> {
        println!("[tcp] Receiving into {} byte buffer", buf.len());
        Ok(0)
    }

    /// Start TLS handshake — transitions to TlsHandshaking.
    /// The Connected state is consumed — you can't send plaintext after starting TLS.
    pub fn start_tls(self) -> TcpConn<TlsHandshaking> {
        println!("[tls] Starting TLS handshake");
        TcpConn { addr: self.addr, _state: PhantomData }
    }

    /// Close the connection cleanly.
    /// Transition: Connected -> Disconnected
    pub fn close(self) -> TcpConn<Disconnected> {
        println!("[tcp] Closing connection to {}", self.addr);
        TcpConn { addr: self.addr, _state: PhantomData }
    }
}

// --- TlsHandshaking: complete handshake to get an Authenticated connection ---
impl TcpConn<TlsHandshaking> {
    /// Complete the TLS handshake.
    /// Transition: TlsHandshaking -> Authenticated
    pub fn finish_handshake(self) -> Result<TcpConn<Authenticated>, io::Error> {
        println!("[tls] Handshake complete");
        Ok(TcpConn { addr: self.addr, _state: PhantomData })
    }

    /// Abort the TLS handshake and fall back to a closed state.
    pub fn abort(self) -> TcpConn<Disconnected> {
        println!("[tls] Handshake aborted");
        TcpConn { addr: self.addr, _state: PhantomData }
    }
}

// --- Authenticated: TLS-encrypted send/receive ---
impl TcpConn<Authenticated> {
    pub fn send_encrypted(&mut self, data: &[u8]) -> Result<usize, io::Error> {
        println!("[tls] Sending {} bytes (encrypted)", data.len());
        Ok(data.len())
    }

    pub fn recv_encrypted(&mut self, buf: &mut [u8]) -> Result<usize, io::Error> {
        println!("[tls] Receiving (encrypted) into {} byte buffer", buf.len());
        Ok(0)
    }

    pub fn close(self) -> TcpConn<Disconnected> {
        println!("[tls] Closing TLS connection to {}", self.addr);
        TcpConn { addr: self.addr, _state: PhantomData }
    }
}

// --- Usage: valid state transitions ---
fn https_request(host: &str, path: &str) -> Result<(), io::Error> {
    // Must connect before sending:
    let disconnected = TcpConn::<Disconnected>::new(format!("{host}:443"));
    let connected = disconnected.connect()?;

    // Must complete TLS before sending encrypted data:
    let handshaking = connected.start_tls();
    let mut authenticated = handshaking.finish_handshake()?;

    // Now we can send/receive:
    let request = format!("GET {path} HTTP/1.1\r\nHost: {host}\r\n\r\n");
    authenticated.send_encrypted(request.as_bytes())?;

    let mut buf = vec![0u8; 4096];
    authenticated.recv_encrypted(&mut buf)?;

    // Clean close:
    let _disconnected = authenticated.close();
    // `authenticated` is moved — cannot use it after close()
    Ok(())
}

fn main() {
    https_request("example.com", "/").unwrap();

    // The following would be COMPILE ERRORS:

    // Cannot send on a disconnected connection:
    // let d = TcpConn::<Disconnected>::new("host:80");
    // d.send(b"hello"); // ERROR: no method `send` on TcpConn<Disconnected>

    // Cannot skip TLS and call send_encrypted on a plain Connected:
    // let conn = TcpConn::<Disconnected>::new("host:443").connect().unwrap();
    // conn.send_encrypted(b"data"); // ERROR: no method on TcpConn<Connected>

    // Cannot use connection after closing:
    // let closed_conn = conn.close();
    // closed_conn.send(b"ghost"); // ERROR: no `send` on TcpConn<Disconnected>

    // Cannot close a connection that's already Disconnected:
    // let d = TcpConn::<Disconnected>::new("host:80");
    // d.close(); // ERROR: no method `close` on TcpConn<Disconnected>
}
```

The typestate pattern in summary:
- State is encoded in the type parameter `S` — there is exactly one valid type for each protocol state.
- Transition methods consume `self` (by value) and return a connection in the new state. The old state ceases to exist at the type level.
- Methods that are invalid in a given state simply don't exist on that `impl` block — the error is "method not found", not a runtime panic.
- `PhantomData<S>` carries the state in the type system with zero runtime cost — the struct has the same layout regardless of `S`.

