// Cargo.toml [dev-dependencies]: proptest = "1"

/// The sorting algorithm under test — insertion sort
/// (can be swapped for any sort to verify properties)
pub fn insertion_sort(mut v: Vec<i32>) -> Vec<i32> {
    let n = v.len();
    for i in 1..n {
        let key = v[i];
        let mut j = i;
        while j > 0 && v[j - 1] > key {
            v[j] = v[j - 1];
            j -= 1;
        }
        v[j] = key;
    }
    v
}

/// Check if a slice is sorted in non-decreasing order
fn is_sorted(v: &[i32]) -> bool {
    v.windows(2).all(|w| w[0] <= w[1])
}

/// Check that two vectors are permutations of each other
/// (same elements, possibly different order)
fn is_permutation(a: &[i32], b: &[i32]) -> bool {
    if a.len() != b.len() { return false; }
    let mut a_sorted = a.to_vec();
    let mut b_sorted = b.to_vec();
    a_sorted.sort_unstable();
    b_sorted.sort_unstable();
    a_sorted == b_sorted
}

#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;
    use proptest::collection::vec;

    // Reusable strategy for test vectors
    fn input_strategy() -> impl Strategy<Value = Vec<i32>> {
        vec(any::<i32>(), 0..200)
    }

    // --- Property 1: Sortedness ---
    // After sorting, the result must be non-decreasing.
    proptest! {
        #[test]
        fn sorted_output_is_sorted(v in input_strategy()) {
            let result = insertion_sort(v);
            prop_assert!(is_sorted(&result),
                "output is not sorted: {result:?}");
        }
    }

    // --- Property 2: Length Preservation ---
    // Sorting must not add or remove elements.
    proptest! {
        #[test]
        fn sort_preserves_length(v in input_strategy()) {
            let original_len = v.len();
            let result = insertion_sort(v);
            prop_assert_eq!(result.len(), original_len,
                "length changed: {} -> {}", original_len, result.len());
        }
    }

    // --- Property 3: Permutation Invariance ---
    // The output must contain the same elements as the input.
    // This catches bugs where elements are dropped or duplicated.
    proptest! {
        #[test]
        fn sort_is_permutation_of_input(v in input_strategy()) {
            let result = insertion_sort(v.clone());
            prop_assert!(is_permutation(&v, &result),
                "output is not a permutation of input\ninput:  {v:?}\noutput: {result:?}");
        }
    }

    // --- Property 4: Idempotence ---
    // Sorting an already-sorted array produces the same array.
    // sort(sort(v)) == sort(v)
    proptest! {
        #[test]
        fn sort_is_idempotent(v in input_strategy()) {
            let once = insertion_sort(v);
            let twice = insertion_sort(once.clone());
            prop_assert_eq!(&once, &twice,
                "sort(sort(v)) != sort(v): {once:?} vs {twice:?}");
        }
    }

    // --- Property 5: Stability analog (monotone under extension) ---
    // If we sort v, then sort v + [min_element], the result is [min_element] ++ sorted(v)
    proptest! {
        #[test]
        fn prepending_min_gives_sorted_result(v in input_strategy()) {
            if v.is_empty() { return Ok(()); }
            let min = *v.iter().min().unwrap();
            let mut extended = v.clone();
            extended.push(min - 1); // element smaller than all others
            let result = insertion_sort(extended);
            prop_assert_eq!(result[0], min - 1,
                "smallest element not at front: {result:?}");
        }
    }

    // --- Property 6: Consistent with std sort ---
    // The gold standard: our sort must agree with std::sort_unstable.
    proptest! {
        #[test]
        fn agrees_with_stdlib_sort(v in input_strategy()) {
            let ours = insertion_sort(v.clone());
            let mut theirs = v;
            theirs.sort_unstable();
            prop_assert_eq!(ours, theirs,
                "our sort disagrees with std");
        }
    }

    // --- Property 7: Input order invariance ---
    // Sorting a reversed input gives the same result as sorting the original.
    proptest! {
        #[test]
        fn order_invariant(v in input_strategy()) {
            let forward = insertion_sort(v.clone());
            let mut rev = v;
            rev.reverse();
            let backward = insertion_sort(rev);
            prop_assert_eq!(forward, backward,
                "sort(v) != sort(rev(v))");
        }
    }

    // --- Regression: specific cases ---
    // Once proptest finds a bug, shrinks to minimal failing case,
    // add it as a fixed regression test:
    #[test]
    fn regression_empty() {
        assert_eq!(insertion_sort(vec![]), vec![]);
    }

    #[test]
    fn regression_single() {
        assert_eq!(insertion_sort(vec![42]), vec![42]);
    }

    #[test]
    fn regression_all_equal() {
        let v = vec![5, 5, 5, 5];
        assert_eq!(insertion_sort(v.clone()), v);
    }

    // --- Custom config: more cases for critical code ---
    proptest! {
        #![proptest_config(ProptestConfig::with_cases(2_000))]
        #[test]
        fn high_confidence_sorted(v in input_strategy()) {
            prop_assert!(is_sorted(&insertion_sort(v)));
        }
    }
}
```

The algebraic properties tested here are the **sort specification**:
1. **Sortedness**: obvious correctness criterion.
2. **Length preservation**: rules out dropping elements.
3. **Permutation**: rules out element duplication or substitution.
4. **Idempotence**: `sort(sort(x)) == sort(x)` — sort is a closure operator.
5. **Consistency with stdlib**: the oracle approach — if both disagree, yours is wrong.
6. **Order invariance**: the result shouldn't depend on input order.

Proptest shrinks failing cases: if `[3, 1, 2, -5, 100]` fails, it shrinks to the minimal vector (e.g., `[1, 0]`) that still triggers the bug, making diagnosis much faster than random inputs.

