// All computation happens at compile time — verified by using in const contexts

const CRC32_POLY: u32 = 0xEDB88320; // IEEE 802.3 polynomial (reversed bit order)

/// Compute a single CRC32 table entry at compile time.
const fn crc32_entry(mut byte: u32) -> u32 {
    let mut i = 0;
    while i < 8 {
        if byte & 1 != 0 {
            byte = (byte >> 1) ^ CRC32_POLY;
        } else {
            byte >>= 1;
        }
        i += 1;
    }
    byte
}

/// Build the full 256-entry CRC32 lookup table at compile time.
/// The result is baked directly into the binary's read-only data section.
const CRC32_TABLE: [u32; 256] = {
    let mut table = [0u32; 256];
    let mut i = 0;
    // Note: for loops are NOT allowed in const fn — use while
    while i < 256 {
        table[i] = crc32_entry(i as u32);
        i += 1;
    }
    table
};

/// Compute CRC32 of a byte slice using the precomputed table.
/// This function runs at runtime but does zero initialization work.
pub fn crc32(data: &[u8]) -> u32 {
    let mut crc = !0u32; // 0xFFFFFFFF
    for &byte in data {
        let idx = ((crc ^ byte as u32) & 0xFF) as usize;
        crc = (crc >> 8) ^ CRC32_TABLE[idx];
    }
    !crc
}

/// Verify the table is correct at compile time (a const assertion)
const _: () = {
    // CRC32 of "123456789" is the standard test vector: 0xCBF43926
    // We can't call crc32() in const context because it takes &[u8],
    // but we can verify individual table entries:
    assert!(CRC32_TABLE[0] == 0);
    assert!(CRC32_TABLE[1] == 0x77073096);
    assert!(CRC32_TABLE[255] == 0x2D02EF8D);
};

// --- Generic compile-time table builder ---

/// A const-evaluated lookup table for any type implementing const computation.
/// Example: sine approximation table for fixed-point math.
const SINE_TABLE_SIZE: usize = 256;

/// Fixed-point sine table: sin(i * π / 128) * 32767, for i in 0..256
/// Avoids floating-point at runtime in embedded/no_std contexts.
const fn fixed_sine(i: usize) -> i16 {
    // Polynomial approximation of sin in const context
    // Uses the identity: sin(x) ≈ x - x³/6 + x⁵/120 for small x
    // Map i -> angle in [0, 2π)
    // For simplicity, use a known precomputed approach via integer math:
    // (This is a pedagogical approximation; production uses proper cordic)
    let angle_steps = SINE_TABLE_SIZE as i64;
    // Approximate: for first quarter [0, 64), use linear interpolation
    // sin(0)=0, sin(64)=1.0 (quarter period)
    let quarter = (angle_steps / 4) as i64;
    let i = i as i64;
    // Map to [0, 1] in first quarter, then mirror
    let q = i % (angle_steps / 4);
    let sign: i64 = if i < angle_steps / 2 { 1 } else { -1 };
    let flip = (i / quarter) % 2 == 1;
    let frac = if flip { quarter - q } else { q };
    // Linear approx within quarter: not accurate but illustrates the pattern
    (sign * frac * 32767 / quarter) as i16
}

const SINE_TABLE: [i16; SINE_TABLE_SIZE] = {
    let mut t = [0i16; SINE_TABLE_SIZE];
    let mut i = 0;
    while i < SINE_TABLE_SIZE {
        t[i] = fixed_sine(i);
        i += 1;
    }
    t
};

// --- Compile-time perfect hash / dispatch table ---

const fn fnv1a_hash(s: &[u8]) -> u32 {
    let mut hash: u32 = 2166136261;
    let mut i = 0;
    while i < s.len() {
        hash ^= s[i] as u32;
        hash = hash.wrapping_mul(16777619);
        i += 1;
    }
    hash
}

// Verify known hashes at compile time
const _HASH_CHECK: () = {
    assert!(fnv1a_hash(b"hello") == 1335831723);
};

// Command dispatch table: map command names (hashed) to IDs
const CMD_QUIT:   u32 = fnv1a_hash(b"quit");
const CMD_STATUS: u32 = fnv1a_hash(b"status");
const CMD_RESET:  u32 = fnv1a_hash(b"reset");

fn dispatch(cmd: &str) -> &'static str {
    match fnv1a_hash(cmd.as_bytes()) {
        x if x == CMD_QUIT   => "shutting down",
        x if x == CMD_STATUS => "all systems nominal",
        x if x == CMD_RESET  => "resetting state",
        _                    => "unknown command",
    }
}

fn main() {
    // CRC32 — table is already in the binary, no init cost
    let data = b"123456789";
    let checksum = crc32(data);
    println!("CRC32 of {:?}: 0x{checksum:08X}", std::str::from_utf8(data).unwrap());
    assert_eq!(checksum, 0xCBF43926, "CRC32 standard test vector failed");

    let msg = b"Hello, const fn!";
    let chk = crc32(msg);
    println!("CRC32 of {:?}: 0x{chk:08X}", std::str::from_utf8(msg).unwrap());

    // Verify first few table entries match known values
    println!("Table[0..4]: {:08X?}", &CRC32_TABLE[..4]);

    // Sine table lookup
    println!("SINE_TABLE[0..8]: {SINE_TABLE:?}",
        SINE_TABLE = &SINE_TABLE[..8]);

    // Command dispatch
    for cmd in ["quit", "status", "reset", "help"] {
        println!("dispatch({cmd:?}) -> {}", dispatch(cmd));
    }
}
```

`const fn` restrictions (stable Rust):
- No `for` loops — use `while` instead.
- No heap allocation (`Box`, `Vec`, `String`).
- No trait objects or closures.
- No floating-point operations in const context (as of Rust 1.82, f64 arithmetic IS allowed in const fn but not transcendentals like `sin`/`cos`).
- `assert!` works in const context (panics at compile time on failure).

The `CRC32_TABLE` is placed in the binary's `.rodata` section — the same section as string literals. It has zero runtime initialization cost and the compiler may even keep it in cache-friendly alignment.

