// Cargo.toml: thiserror = "1", anyhow = "1"
use thiserror::Error;
use std::{io, num::ParseIntError, path::PathBuf};

#[derive(Debug, Error)]
pub enum ConfigError {
    #[error("config file not found: {path}")]
    NotFound { path: PathBuf },

    #[error("failed to read {path}: {source}")]
    ReadFailed { path: PathBuf, #[source] source: io::Error },

    #[error("invalid port: {source}")]
    InvalidPort { #[from] source: ParseIntError },

    #[error("missing required field: {field}")]
    MissingField { field: &'static str },
}

#[derive(Debug, Error)]
pub enum AppError {
    #[error("config: {0}")]
    Config(#[from] ConfigError),

    #[error("io: {0}")]
    Io(#[from] io::Error),
}

fn parse_port(raw: &str) -> Result<u16, ConfigError> {
    raw.parse::<u16>().map_err(|e| ConfigError::InvalidPort { source: e })
}

fn load_config(path: &std::path::Path) -> Result<u16, ConfigError> {
    let content = std::fs::read_to_string(path).map_err(|e| ConfigError::ReadFailed {
        path: path.to_path_buf(), source: e,
    })?;
    let port_str = content.lines()
        .find(|l| l.starts_with("port="))
        .ok_or(ConfigError::MissingField { field: "port" })?
        .trim_start_matches("port=");
    parse_port(port_str)
}

fn run(path: &std::path::Path) -> Result<(), AppError> {
    let port = load_config(path)?; // ConfigError -> AppError via #[from]
    println!("Listening on port {port}");
    Ok(())
}

