use std::collections::HashMap;

/// Capabilities a plugin can advertise
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum Capability {
    Parse,
    Compress,
    Encrypt,
    Serialize,
}

/// The plugin trait -- object-safe
pub trait Plugin: Send + Sync {
    fn name(&self) -> &str;
    fn capabilities(&self) -> &[Capability];
    fn execute(&self, input: &[u8]) -> Result<Vec<u8>, String>;
    fn priority(&self) -> u32 { 100 } // higher = preferred
}

pub struct PluginRegistry {
    plugins: Vec<Box<dyn Plugin>>,
}

impl PluginRegistry {
    pub fn new() -> Self { PluginRegistry { plugins: Vec::new() } }

    pub fn register(&mut self, plugin: Box<dyn Plugin>) {
        println!("[registry] registered '{}' with caps {:?}", plugin.name(), plugin.capabilities());
        self.plugins.push(plugin);
    }

    /// Find all plugins that have `cap`, sorted by priority desc
    pub fn find_capable(&self, cap: &Capability) -> Vec<&dyn Plugin> {
        let mut capable: Vec<_> = self.plugins.iter()
            .filter(|p| p.capabilities().contains(cap))
            .map(|p| p.as_ref())
            .collect();
        capable.sort_by(|a, b| b.priority().cmp(&a.priority()));
        capable
    }

    /// Dispatch to the highest-priority plugin capable of `cap`
    pub fn dispatch(&self, cap: &Capability, input: &[u8]) -> Result<Vec<u8>, String> {
        self.find_capable(cap)
            .first()
            .ok_or_else(|| format!("no plugin for {cap:?}"))?
            .execute(input)
    }

    /// Try plugins in priority order, stop on first success
    pub fn dispatch_fallback(&self, cap: &Capability, input: &[u8]) -> Result<Vec<u8>, String> {
        let candidates = self.find_capable(cap);
        if candidates.is_empty() {
            return Err(format!("no plugin for {cap:?}"));
        }
        let mut last_err = String::new();
        for p in candidates {
            match p.execute(input) {
                Ok(r) => return Ok(r),
                Err(e) => { eprintln!("[{}] failed: {e}", p.name()); last_err = e; }
            }
        }
        Err(last_err)
    }

    pub fn list(&self) -> Vec<&str> { self.plugins.iter().map(|p| p.name()).collect() }
}

// --- Concrete plugins ---

struct GzipPlugin;
impl Plugin for GzipPlugin {
    fn name(&self) -> &str { "gzip" }
    fn capabilities(&self) -> &[Capability] { &[Capability::Compress] }
    fn priority(&self) -> u32 { 200 }
    fn execute(&self, input: &[u8]) -> Result<Vec<u8>, String> {
        // Simulate: prepend a "gzip header"
        let mut out = b"GZIP:".to_vec();
        out.extend_from_slice(input);
        Ok(out)
    }
}

struct JsonPlugin;
impl Plugin for JsonPlugin {
    fn name(&self) -> &str { "json-serializer" }
    fn capabilities(&self) -> &[Capability] { &[Capability::Serialize, Capability::Parse] }
    fn execute(&self, input: &[u8]) -> Result<Vec<u8>, String> {
        let s = std::str::from_utf8(input).map_err(|e| e.to_string())?;
        Ok(format!("{{\"data\":\"{s}\"}}").into_bytes())
    }
}

struct FalliblePlugin { fail: bool }
impl Plugin for FalliblePlugin {
    fn name(&self) -> &str { if self.fail { "bad-compressor" } else { "zstd" } }
    fn capabilities(&self) -> &[Capability] { &[Capability::Compress] }
    fn priority(&self) -> u32 { if self.fail { 300 } else { 50 } }
    fn execute(&self, input: &[u8]) -> Result<Vec<u8>, String> {
        if self.fail { Err("compressor unavailable".into()) }
        else {
            let mut out = b"ZSTD:".to_vec();
            out.extend_from_slice(input);
            Ok(out)
        }
    }
}

fn main() {
    let mut reg = PluginRegistry::new();
    reg.register(Box::new(GzipPlugin));
    reg.register(Box::new(JsonPlugin));
    reg.register(Box::new(FalliblePlugin { fail: true  })); // priority 300 but fails
    reg.register(Box::new(FalliblePlugin { fail: false })); // priority 50, succeeds

    println!("\nRegistered plugins: {:?}", reg.list());

    // Dispatch to highest-priority Compress plugin
    let data = b"hello world";
    println!("\ndispatch(Compress):");
    match reg.dispatch(&Capability::Compress, data) {
        Ok(r) => println!("  {}", String::from_utf8_lossy(&r)),
        Err(e) => println!("  error: {e}"),
    }

    // Fallback: tries bad-compressor first (priority 300), falls back to zstd
    println!("\ndispatch_fallback(Compress):");
    match reg.dispatch_fallback(&Capability::Compress, data) {
        Ok(r) => println!("  {}", String::from_utf8_lossy(&r)),
        Err(e) => println!("  error: {e}"),
    }

    // Serialize
    println!("\ndispatch(Serialize):");
    match reg.dispatch(&Capability::Serialize, b"test") {
        Ok(r) => println!("  {}", String::from_utf8_lossy(&r)),
        Err(e) => println!("  error: {e}"),
    }

    // No plugin for Encrypt
    println!("\ndispatch(Encrypt): {:?}", reg.dispatch(&Capability::Encrypt, b""));
}
```

`Box<dyn Plugin>` is the key -- it erases the concrete plugin type while retaining the virtual method table for `name`, `capabilities`, `execute`, and `priority`. The registry holds heterogeneous plugins in a single `Vec`. For dynamic loading from `.so` files, replace `Box::new(GzipPlugin)` with `PluginHandle::load("gzip.so")` using `libloading`.

