// Unsafe Rust: you take on the responsibility the borrow checker cannot verify.
// Rule: the unsafe BLOCK/fn must uphold the invariants -- callers of safe APIs are protected.

use std::ptr::NonNull;
use std::marker::PhantomData;

/// A non-null, owned heap allocation of type T.
/// Semantically equivalent to Box<T> but illustrates the unsafe operations.
pub struct OwnedPtr<T> {
    ptr: NonNull<T>,
    _owns: PhantomData<T>, // tells the drop checker we own a T
}

// SAFETY: OwnedPtr<T> is Send/Sync if T is, because we have exclusive ownership.
unsafe impl<T: Send> Send for OwnedPtr<T> {}
unsafe impl<T: Sync> Sync for OwnedPtr<T> {}

impl<T> OwnedPtr<T> {
    /// Allocate a new T on the heap and wrap it.
    pub fn new(value: T) -> Self {
        // Box::new then into_raw: safe way to get a non-null pointer we own.
        let raw = Box::into_raw(Box::new(value));
        OwnedPtr {
            // SAFETY: Box::into_raw never returns null.
            ptr: unsafe { NonNull::new_unchecked(raw) },
            _owns: PhantomData,
        }
    }

    pub fn as_ref(&self) -> &T {
        // SAFETY: ptr is non-null, properly aligned, and points to a valid T
        // that we own and have not given out a mutable reference to.
        unsafe { self.ptr.as_ref() }
    }

    pub fn as_mut(&mut self) -> &mut T {
        // SAFETY: ptr is non-null, valid, and we have &mut self so no other
        // mutable references can exist to this location.
        unsafe { self.ptr.as_mut() }
    }

    /// Consume the wrapper and return the value, freeing the heap allocation.
    pub fn into_inner(self) -> T {
        // SAFETY: ptr was created from Box::into_raw; reconstructing the Box
        // and calling into_inner transfers ownership correctly.
        let val = unsafe { *Box::from_raw(self.ptr.as_ptr()) };
        std::mem::forget(self); // skip our Drop impl which would double-free
        val
    }
}

impl<T> Drop for OwnedPtr<T> {
    fn drop(&mut self) {
        // SAFETY: ptr was created via Box::into_raw. We are the sole owner
        // (no other references exist at drop time). Reconstructing the Box
        // and dropping it frees the memory exactly once.
        unsafe { drop(Box::from_raw(self.ptr.as_ptr())); }
    }
}

impl<T: std::fmt::Debug> std::fmt::Debug for OwnedPtr<T> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "OwnedPtr({:?})", self.as_ref())
    }
}

// --- Demonstrating unsafe rules ---

/// SAFETY requirements for callers of this raw function:
/// - `ptr` must be non-null
/// - `ptr` must point to a valid, initialized T
/// - `ptr` must not alias any other mutable reference
/// - `len` must be the actual length of the slice starting at ptr
unsafe fn sum_raw(ptr: *const i32, len: usize) -> i64 {
    // std::slice::from_raw_parts requires all of the above
    let slice = std::slice::from_raw_parts(ptr, len);
    slice.iter().map(|&x| x as i64).sum()
}

/// Safe wrapper -- the compiler verifies all preconditions via the borrow checker
fn sum_slice(data: &[i32]) -> i64 {
    // SAFETY: &[i32] guarantees non-null, valid, non-aliased, correct length.
    unsafe { sum_raw(data.as_ptr(), data.len()) }
}

// --- Interior mutability via raw pointer (UnsafeCell pattern) ---

use std::cell::UnsafeCell;

pub struct UnsafeOnce<T> {
    cell: UnsafeCell<Option<T>>,
    initialized: std::sync::atomic::AtomicBool,
}

impl<T: Send> UnsafeOnce<T> {
    pub const fn new() -> Self {
        UnsafeOnce {
            cell: UnsafeCell::new(None),
            initialized: std::sync::atomic::AtomicBool::new(false),
        }
    }

    /// Initialize the cell. Panics if called more than once.
    pub fn init(&self, value: T) {
        use std::sync::atomic::Ordering;
        assert!(!self.initialized.swap(true, Ordering::SeqCst), "init called twice");
        // SAFETY: we verified via atomic that this is the first and only init call.
        // No other references exist to the cell at this point.
        unsafe { *self.cell.get() = Some(value); }
    }

    /// Get the value. Returns None if not yet initialized.
    pub fn get(&self) -> Option<&T> {
        // SAFETY: after init, the cell is never mutated again.
        // The shared reference &T is valid for the cell's lifetime.
        unsafe { (*self.cell.get()).as_ref() }
    }
}

fn main() {
    let mut p = OwnedPtr::new(42i32);
    println!("{p:?}");
    *p.as_mut() *= 2;
    println!("{p:?}");
    let val = p.into_inner();
    println!("val={val}");

    let data = [1, 2, 3, 4, 5];
    println!("sum={}", sum_slice(&data));

    let once = UnsafeOnce::new();
    once.init("hello");
    println!("once={:?}", once.get());
}
```

Unsafe Rust rules:
1. `unsafe` blocks do NOT disable the borrow checker -- they allow 5 specific operations: raw pointer deref, calling unsafe fns, implementing unsafe traits, accessing mutable statics, and accessing union fields.
2. Every `unsafe` block must carry a `// SAFETY:` comment explaining WHY the invariants hold.
3. `NonNull<T>` is preferred over `*mut T` -- it is non-null by construction and coerces correctly.
4. `PhantomData<T>` is required when a struct logically owns a `T` through a raw pointer -- without it, the drop checker cannot reason about lifetimes and Send/Sync impls are unsound.

```rust
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};

#[derive(Debug, Clone)]
pub struct TokenBucket {
    /// Maximum tokens (burst capacity)
    capacity: f64,
    /// Current tokens available
    tokens: f64,
    /// Tokens added per second
    refill_rate: f64,
    /// Last refill time
    last_refill: Instant,
}

impl TokenBucket {
    /// Create a bucket that allows `capacity` burst requests and refills at `per_second` tokens/sec.
    pub fn new(capacity: f64, per_second: f64) -> Self {
        TokenBucket {
            capacity,
            tokens: capacity,
            refill_rate: per_second,
            last_refill: Instant::now(),
        }
    }

    /// Refill tokens based on elapsed time.
    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill).as_secs_f64();
        self.tokens = (self.tokens + elapsed * self.refill_rate).min(self.capacity);
        self.last_refill = now;
    }

    /// Try to consume `n` tokens. Returns true if allowed.
    pub fn try_consume(&mut self, n: f64) -> bool {
        self.refill();
        if self.tokens >= n {
            self.tokens -= n;
            true
        } else {
            false
        }
    }

    /// Consume 1 token. Returns true if allowed.
    pub fn allow(&mut self) -> bool { self.try_consume(1.0) }

    /// How long until `n` tokens are available?
    pub fn wait_time(&mut self, n: f64) -> Option<Duration> {
        self.refill();
        if self.tokens >= n {
            None
        } else {
            let deficit = n - self.tokens;
            let secs = deficit / self.refill_rate;
            Some(Duration::from_secs_f64(secs))
        }
    }

    pub fn tokens_available(&mut self) -> f64 { self.refill(); self.tokens }
}

/// Thread-safe rate limiter wrapping a TokenBucket.
#[derive(Clone)]
pub struct RateLimiter(Arc<Mutex<TokenBucket>>);

impl RateLimiter {
    pub fn new(capacity: f64, per_second: f64) -> Self {
        RateLimiter(Arc::new(Mutex::new(TokenBucket::new(capacity, per_second))))
    }

    pub fn allow(&self) -> bool {
        self.0.lock().unwrap().allow()
    }

    pub fn try_consume(&self, n: f64) -> bool {
        self.0.lock().unwrap().try_consume(n)
    }

    /// Block until `n` tokens are available, then consume them.
    pub fn wait_and_consume(&self, n: f64) {
        loop {
            let wait = self.0.lock().unwrap().wait_time(n);
            match wait {
                None => {
                    self.0.lock().unwrap().try_consume(n);
                    return;
                }
                Some(d) => std::thread::sleep(d),
            }
        }
    }

    pub fn tokens_available(&self) -> f64 {
        self.0.lock().unwrap().tokens_available()
    }
}

fn main() {
    use std::thread;

    // Single-threaded demo
    let mut bucket = TokenBucket::new(5.0, 2.0); // burst=5, refill=2/sec
    println!("Initial tokens: {:.1}", bucket.tokens_available());

    for i in 0..7 {
        if bucket.allow() {
            println!("Request {i}: ALLOWED (tokens={:.1})", bucket.tokens_available());
        } else {
            println!("Request {i}: DENIED  (tokens={:.1})", bucket.tokens_available());
        }
    }

    println!("\nWaiting 1 second for refill...");
    thread::sleep(Duration::from_secs(1));
    println!("Tokens after 1s: {:.1}", bucket.tokens_available()); // ~2 tokens added

    // Thread-safe shared rate limiter
    let limiter = RateLimiter::new(10.0, 5.0); // burst=10, 5 req/sec
    let mut handles = vec![];

    for t in 0..4 {
        let lim = limiter.clone();
        handles.push(thread::spawn(move || {
            for r in 0..5 {
                if lim.allow() {
                    println!("[thread {t}] request {r}: OK");
                } else {
                    println!("[thread {t}] request {r}: rate limited");
                }
                thread::sleep(Duration::from_millis(50));
            }
        }));
    }
    for h in handles { h.join().unwrap(); }

    // wait_and_consume: blocks until tokens available
    println!("\nWait-and-consume demo:");
    let strict = RateLimiter::new(2.0, 1.0); // 1 req/sec, burst=2
    for i in 0..4 {
        let before = Instant::now();
        strict.wait_and_consume(1.0);
        println!("Request {i} at {:.2}s", before.elapsed().as_secs_f64());
    }
}
```

Token bucket algorithm: tokens accumulate at `refill_rate` per second up to `capacity` (burst). Each request costs 1 token. `refill()` is lazy -- it computes elapsed time and adds tokens only when called, avoiding background threads. `Arc<Mutex<TokenBucket>>` provides thread-safety; the lock is held only for the short duration of `refill + consume` so contention is minimal.

