// === Demonstration: what the macro generates ===

// #[derive(IntEnum)]
// #[repr(u8)]
// enum Status { Pending = 0, Active = 1, Suspended = 2, Closed = 10 }

// Generated code:
#[derive(Debug, Clone, Copy, PartialEq)]
#[repr(u8)]
enum Status { Pending = 0, Active = 1, Suspended = 2, Closed = 10 }

impl From<Status> for u8 {
    fn from(v: Status) -> u8 {
        match v {
            Status::Pending   => 0u8,
            Status::Active    => 1u8,
            Status::Suspended => 2u8,
            Status::Closed    => 10u8,
        }
    }
}

impl TryFrom<u8> for Status {
    type Error = String;
    fn try_from(n: u8) -> Result<Self, String> {
        match n {
            0  => Ok(Status::Pending),
            1  => Ok(Status::Active),
            2  => Ok(Status::Suspended),
            10 => Ok(Status::Closed),
            _  => Err(format!("invalid discriminant for Status: {n}")),
        }
    }
}

// #[derive(IntEnum)]
// #[repr(i32)]
// enum ErrorCode { Ok = 0, NotFound = 404, ServerError = 500, Unauthorized = 401 }

#[derive(Debug, Clone, Copy, PartialEq)]
#[repr(i32)]
enum ErrorCode { Ok = 0, NotFound = 404, Unauthorized = 401, ServerError = 500 }

impl From<ErrorCode> for i32 {
    fn from(v: ErrorCode) -> i32 {
        match v {
            ErrorCode::Ok           =>   0,
            ErrorCode::NotFound     => 404,
            ErrorCode::Unauthorized => 401,
            ErrorCode::ServerError  => 500,
        }
    }
}

impl TryFrom<i32> for ErrorCode {
    type Error = String;
    fn try_from(n: i32) -> Result<Self, String> {
        match n {
            0   => Ok(ErrorCode::Ok),
            404 => Ok(ErrorCode::NotFound),
            401 => Ok(ErrorCode::Unauthorized),
            500 => Ok(ErrorCode::ServerError),
            _   => Err(format!("invalid error code: {n}")),
        }
    }
}

fn main() {
    // From: enum -> integer
    let s = Status::Active;
    let n: u8 = s.into();
    println!("{s:?} -> {n}");  // Active -> 1

    // TryFrom: integer -> enum
    let back = Status::try_from(10u8).unwrap();
    println!("10 -> {back:?}");  // Closed

    let bad = Status::try_from(99u8);
    println!("99 -> {bad:?}");  // Err(...)

    // ErrorCode
    let code = ErrorCode::NotFound;
    let raw: i32 = code.into();
    println!("{code:?} -> {raw}");  // NotFound -> 404

    let parsed = ErrorCode::try_from(500i32).unwrap();
    println!("500 -> {parsed:?}");  // ServerError

    // Useful for serialization/protocol parsing:
    let bytes: Vec<u8> = vec![0, 1, 2, 10, 99];
    for b in bytes {
        match Status::try_from(b) {
            Ok(s)  => println!("  {b} => {s:?}"),
            Err(e) => println!("  {b} => ERROR: {e}"),
        }
    }
}
```

Macro implementation notes: the `repr` attribute is parsed from `input.attrs` to determine the integer type. Each variant's discriminant is computed cumulatively (auto-increment from 0, or explicit value). Two `impl` blocks are generated: `From<Enum> for IntType` (infallible, match on variant) and `TryFrom<IntType> for Enum` (fallible, match on integer values, fallthrough to `Err`). Run `cargo expand` to see the exact generated code.
